INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (30000, 15, "", 0, 0, 0, 1, 24001, 35, "", 2);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (40000, 1, "", 0, 0, 0, 100, 91002, 36, "", 8);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (40001, 1, "今日は記念日、お祝いですね！\n焼肉、お寿司、ピザ、ケーキ～☆\nあなたとパーティできるなんて、\n幸せです～♪", 1, 107501, 0, 150, 91002, 37, "ぺコリーヌ", 8);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (40001, 2, "この記念日を迎えられたのは、\n主さまの器量の賜物\nさすがは主さまでございます\nえらい、えらい♪", 1, 107601, 0, 150, 91002, 38, "コッコロ", 8);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (40001, 3, "あんたもけっこうやるじゃない！\nちょっとは…割と…け、けっこう\n見直しちゃったわ\n褒めてあげる♪", 1, 107801, 0, 150, 91002, 39, "キャル", 8);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (40001, 4, "あなたと私にとって、\n今日は特別な日\nあなたの支えがあるから、\n私は頑張れるんです！", 1, 107701, 0, 150, 91002, 40, "スズメ", 8);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (40001, 5, "今日はキミにとっての\n特別な記念日だにゃ\nキミの活躍にはいつも\n猫ながら感謝してるにゃ～♪", 1, 107901, 0, 150, 91002, 41, "タマキ", 8);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (40001, 6, "う～かき氷食べ過ぎて、\n身体が冷えちゃいました…\nあなたの体温で温めてください！\nギューーッ♪", 2, 107501, 0, 150, 91002, 42, "ぺコリーヌ", 8);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (40001, 7, "夏は危険がいっぱいと申します…\nですが、わたくしが主さまを\nしっかりとお守りいたしますよ", 2, 107601, 0, 150, 91002, 43, "コッコロ", 8);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (40001, 8, "ん～なんであんたと、ひと夏を\n過ごすことになったのかな…\n結構楽しいからいいけど！\nさ、まだまだ遊ぶわよ！", 2, 107801, 0, 150, 91002, 44, "キャル", 8);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (40001, 9, "あなたと過ごすはじめての夏…\nいまからドキドキが止まりません\n楽しくて素敵な思い出が、\nまた一つ増えるんですね♪", 2, 107701, 0, 150, 91002, 45, "スズメ", 8);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (40001, 10, "夏は一番の稼ぎ時にゃのに、\n今年はキミと過ごしたいって\n思ってるにゃ楽しい思い出\n増やしてくれるかにゃ？", 2, 107901, 0, 150, 91002, 46, "タマキ", 8);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (40003, 1, "", 0, 0, 0, 150, 91002, 57, "", 8);
