INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (40011, 1, "もうすぐ、みなさまに\nお会いできるのですね。\n胸が高鳴ってしまいます……\n", 1, 125801, 0, 1, 24001, 321, "リリ", 2);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (40011, 2, "初めまして、クリアです♪\nみなさんと一緒に冒険するの\nとっても楽しみにしてます", 1, 126001, 0, 1, 24001, 322, "クリア", 2);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (40011, 3, "んーと。\nこれ、あげる。\nはい", 1, 126101, 0, 1, 24001, 323, "プレシア", 2);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (40011, 4, "あらためまして……\n【アルターメイデン】の\nギルドマスター、リリと申します", 2, 125801, 0, 1, 24001, 324, "リリ", 2);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (40011, 5, "こんにちは、お兄さん♪\n【アルターメイデン】の\nクリアです", 2, 126001, 0, 1, 24001, 325, "クリア", 2);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (40011, 6, "お兄。\nきてくれて、うれしい", 2, 126101, 0, 1, 24001, 326, "プレシア", 2);
